BEGIN TRANSACTION;
CREATE TABLE `accounts` (`id` text,`user_id` text,`type` text,`provider` text,`provider_account_id` text,`refresh_token` text,`access_token` text,`expires_at` integer,`token_type` text,`scope` text,`id_token` text,`session_state` text,`created_at` datetime,`updated_at` datetime,`deleted_at` datetime,PRIMARY KEY (`id`),CONSTRAINT `fk_users_accounts` FOREIGN KEY (`user_id`) REFERENCES `users`(`id`));
CREATE TABLE `anomaly_records` (`id` text,`type` text,`severity` text,`title` text,`description` text,`session_id` text,`metadata` text,`is_resolved` numeric DEFAULT false,`resolved_at` datetime,`created_at` datetime,`deleted_at` datetime,PRIMARY KEY (`id`));

